Javascript.validate:
var val = Services.getValue(AmntToInvest.dataBinding);
var err = validateCurrencyValue(val, 99999999.99);
if( null == err )
{	Services.setValue(AmntToInvest.dataBinding, WPU.formatToTwoDP(val));
}
return err;

