function DefaultCurrency613() {}
DefaultCurrency613.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency613.tabIndex = -1;
DefaultCurrency613.maxLength = 1;
DefaultCurrency613.isReadOnly = function(){return true;}
DefaultCurrency613.isTemporary = function(){return true;}
DefaultCurrency613.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency613.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
